@if (TotalPages > 1)
{
    <nav aria-label="Product catalog pagination">
        <ul class="pagination justify-content-center mt-4">
            <li class="page-item @(Page <= 1 ? "disabled" : "")">
                <button class="page-link" @onclick="@(() => OnPageChanged.InvokeAsync(Page - 1))" disabled="@(Page <= 1)">
                    Previous
                </button>
            </li>

            @foreach (var p in GetPageNumbers())
            {
                <li class="page-item @(p == Page ? "active" : "")">
                    <button class="page-link" @onclick="@(() => OnPageChanged.InvokeAsync(p))">@p</button>
                </li>
            }

            <li class="page-item @(Page >= TotalPages ? "disabled" : "")">
                <button class="page-link" @onclick="@(() => OnPageChanged.InvokeAsync(Page + 1))" disabled="@(Page >= TotalPages)">
                    Next
                </button>
            </li>
        </ul>
    </nav>
}

@code {
    [Parameter] public int Page { get; set; } = 1;
    [Parameter] public int TotalPages { get; set; }
    [Parameter] public EventCallback<int> OnPageChanged { get; set; }

    private IEnumerable<int> GetPageNumbers()
    {
        const int maxVisible = 7;
        if (TotalPages <= maxVisible)
            return Enumerable.Range(1, TotalPages);

        var start = Math.Max(1, Page - maxVisible / 2);
        var end = Math.Min(TotalPages, start + maxVisible - 1);
        if (end - start + 1 < maxVisible)
            start = Math.Max(1, end - maxVisible + 1);

        return Enumerable.Range(start, end - start + 1);
    }
}

