+@page "/catalog"
+@using sv_7eb8f253a93a4552a8a756debaa3d10b.Services
+@rendermode InteractiveServer
+@inject IProductService ProductService
+
+<PageTitle>Product Catalog</PageTitle>
+
+<h3 class="mb-3">Product Catalog</h3>
+
+<div class="row">
+    @* Sidebar *@
+    <div class="col-md-3">
+        <div class="border rounded">
+            <CatalogFilters Categories="_categories"
+                            OnApplyFilters="HandleApplyFilters"
+                            OnClearFilters="HandleClearFilters" />
+        </div>
+    </div>
+
+    @* Main Content *@
+    <div class="col-md-9">
+        @if (_error is not null)
+        {
+            <div class="alert alert-danger" role="alert">
+                <strong>Error:</strong> @_error
+                <button class="btn btn-sm btn-outline-danger ms-2" @onclick="RetryLoad">Retry</button>
+            </div>
+        }
+        else if (_loading)
+        {
+            <div class="text-center py-5">
+                <div class="spinner-border text-primary" role="status">
+                    <span class="visually-hidden">Loading...</span>
+                </div>
+                <p class="mt-2 text-muted">Loading products…</p>
+            </div>
+        }
+        else if (_result is null || _result.Items.Count == 0)
+        {
+            <div class="text-center py-5">
+                <p class="text-muted fs-5">No products found matching your criteria.</p>
+                <button class="btn btn-outline-primary" @onclick="HandleClearFilters">Clear Filters</button>
+            </div>
+        }
+        else
+        {
+            <CatalogToolbar SortBy="@_sortBy"
+                            TotalCount="_result.TotalCount"
+                            Page="_result.Page"
+                            PageSize="_result.PageSize"
+                            OnSortChanged="HandleSortChanged" />
+
+            <ProductGrid Products="_result.Items"
+                         OnProductSelected="HandleProductSelected"
+                         OnAddToCart="HandleAddToCart" />
+
+            <CatalogPagination Page="_result.Page"
+                               TotalPages="_totalPages"
+                               OnPageChanged="HandlePageChanged" />
+        }
+    </div>
+</div>
+
+@code {
+    private List<string>? _categories;
+    private PagedResult<Product>? _result;
+    private bool _loading = true;
+    private string? _error;
+    private string _sortBy = "price_asc";
+    private int _page = 1;
+    private const int PageSize = 12;
+
+    private ProductFilter _filter = new(null, null, null, false);
+
+    private int _totalPages => _result is null || _result.PageSize == 0
+        ? 0
+        : (int)Math.Ceiling((double)_result.TotalCount / _result.PageSize);
+
+    [Parameter] public EventCallback<Product> OnProductSelected { get; set; }
+    [Parameter] public EventCallback<Product> OnAddToCart { get; set; }
+
+    protected override async Task OnInitializedAsync()
+    {
+        await LoadDataAsync();
+    }
+
+    private async Task LoadDataAsync()
+    {
+        _loading = true;
+        _error = null;
+
+        try
+        {
+            if (_categories is null)
+            {
+                _categories = await ProductService.GetCategoriesAsync();
+            }
+            _result = await ProductService.SearchAsync(_filter, _sortBy, _page, PageSize);
+        }
+        catch (Exception ex)
+        {
+            _error = ex.Message;
+        }
+        finally
+        {
+            _loading = false;
+        }
+    }
+
+    private async Task HandleApplyFilters(CatalogFilters.ProductFilterState state)
+    {
+        _filter = new ProductFilter(state.Categories, state.MinPrice, state.MaxPrice, state.InStockOnly);
+        _page = 1;
+        await LoadDataAsync();
+    }
+
+    private async Task HandleClearFilters()
+    {
+        _filter = new ProductFilter(null, null, null, false);
+        _page = 1;
+        await LoadDataAsync();
+    }
+
+    private async Task HandleSortChanged(string sortBy)
+    {
+        _sortBy = sortBy;
+        _page = 1;
+        await LoadDataAsync();
+    }
+
+    private async Task HandlePageChanged(int page)
+    {
+        _page = page;
+        await LoadDataAsync();
+    }
+
+    private async Task HandleProductSelected(Product product)
+    {
+        await OnProductSelected.InvokeAsync(product);
+    }
+
+    private async Task HandleAddToCart(Product product)
+    {
+        await OnAddToCart.InvokeAsync(product);
+    }
+
+    private async Task RetryLoad() => await LoadDataAsync();
+}
+
